3_real_world_example.code:
const user = {
  name: 'Alice',
  // Use a regular function for the outer method so it binds 'this' to user
  delayedGreeting() {
    // Use an ARROW function for the callback so it DOESN'T bind a new 'this'
    setTimeout(() => {
      // The arrow function looks up and grabs 'this' from delayedGreeting!
      console.log(`Hello, I am ${this.name}`); 
    }, 1000);
  }
};
user.delayedGreeting(); // 'Hello, I am Alice' (Works perfectly!)

